#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const rootSuite = createSuite('');
let currentSuite = rootSuite;
let hasFailures = false;

function createSuite(name) {
  return {
    name,
    suites: [],
    tests: [],
    beforeEach: [],
    afterEach: [],
  };
}

global.describe = (name, fn) => {
  const suite = createSuite(name);
  currentSuite.suites.push(suite);
  const previous = currentSuite;
  currentSuite = suite;
  try {
    fn();
  } finally {
    currentSuite = previous;
  }
};

global.beforeEach = (fn) => {
  currentSuite.beforeEach.push(fn);
};

global.afterEach = (fn) => {
  currentSuite.afterEach.push(fn);
};

global.test = (name, fn) => {
  currentSuite.tests.push({ name, fn });
};

global.expect = (received) => new Expectation(received);

class Expectation {
  constructor(received) {
    this.received = received;
  }

  toBe(expected) {
    if (this.received !== expected) {
      throw new Error(`Expected ${formatValue(this.received)} to be ${formatValue(expected)}`);
    }
  }

  toEqual(expected) {
    if (!deepEqual(this.received, expected)) {
      throw new Error(`Expected ${formatValue(this.received)} to equal ${formatValue(expected)}`);
    }
  }

  toMatchObject(expected) {
    if (!matchObject(this.received, expected)) {
      throw new Error(`Expected ${formatValue(this.received)} to match object ${formatValue(expected)}`);
    }
  }

  toHaveLength(length) {
    if (!this.received || typeof this.received.length !== 'number') {
      throw new Error(`Expected value with length but received ${formatValue(this.received)}`);
    }
    if (this.received.length !== length) {
      throw new Error(`Expected length ${length} but received ${this.received.length}`);
    }
  }
}

function formatValue(value) {
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function deepEqual(a, b) {
  if (Object.is(a, b)) {
    return true;
  }

  if (typeof a !== typeof b) {
    return false;
  }

  if (a && b && typeof a === 'object') {
    const aKeys = Object.keys(a);
    const bKeys = Object.keys(b);
    if (aKeys.length !== bKeys.length) {
      return false;
    }
    for (const key of aKeys) {
      if (!deepEqual(a[key], b[key])) {
        return false;
      }
    }
    return true;
  }

  return false;
}

function matchObject(received, expected) {
  if (!received || typeof received !== 'object') {
    return false;
  }
  for (const [key, value] of Object.entries(expected)) {
    if (!deepEqual(received[key], value)) {
      return false;
    }
  }
  return true;
}

async function runSuite(suite, ancestors = []) {
  const lineage = ancestors.concat(suite);
  for (const child of suite.suites) {
    await runSuite(child, lineage);
  }

  for (const test of suite.tests) {
    const hookLineage = ancestors.concat(suite);
    const befores = hookLineage.flatMap((s) => s.beforeEach);
    const afters = hookLineage
      .flatMap((s) => s.afterEach)
      .reverse();

    try {
      for (const hook of befores) {
        await hook();
      }
      await test.fn();
      console.log(`\x1b[32m✓\x1b[0m ${[...ancestors.map((s) => s.name), suite.name, test.name].filter(Boolean).join(' > ')}`);
    } catch (error) {
      hasFailures = true;
      console.error(`\x1b[31m✗\x1b[0m ${[...ancestors.map((s) => s.name), suite.name, test.name].filter(Boolean).join(' > ')}`);
      console.error(error.stack || error.toString());
    } finally {
      for (const hook of afters) {
        try {
          await hook();
        } catch (error) {
          hasFailures = true;
          console.error('Error in afterEach hook');
          console.error(error.stack || error.toString());
        }
      }
    }
  }
}

function findTestFiles(startDir) {
  const entries = fs.readdirSync(startDir, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    const fullPath = path.join(startDir, entry.name);
    if (entry.isDirectory()) {
      if (entry.name === 'node_modules') {
        continue;
      }
      files.push(...findTestFiles(fullPath));
    } else if (entry.isFile() && /\.test\.js$/.test(entry.name)) {
      files.push(fullPath);
    }
  }

  return files;
}

function loadTests(files) {
  for (const file of files) {
    require(file);
  }
}

(async function main() {
  const args = process.argv.slice(2);
  let testFiles = [];
  if (args.length === 0) {
    testFiles = findTestFiles(process.cwd());
  } else {
    testFiles = args.map((arg) => path.resolve(process.cwd(), arg));
  }

  if (testFiles.length === 0) {
    console.warn('No test files found.');
    return;
  }

  loadTests(testFiles);
  await runSuite(rootSuite, []);

  if (hasFailures) {
    process.exit(1);
  }
})();
